1	import { Game } from "@/types/api-contract";
2	
3	const IN_PROGRESS_STATUSES = new Set([
4	  "STATUS_IN_PROGRESS",
5	  "STATUS_HALFTIME",
6	  "STATUS_END_PERIOD",
7	]);
8	
9	const SCHEDULED_STATUS = "STATUS_SCHEDULED";
10	// Soccer finals arrive as STATUS_FULL_TIME rather than STATUS_FINAL.
11	const FINAL_STATUSES = new Set(["STATUS_FINAL", "STATUS_FULL_TIME"]);
12	const POSTPONED_STATUS = "STATUS_POSTPONED";
13	const MAX_RECENTLY_STARTED_GAME_AGE_MS = 6 * 60 * 60 * 1000;
14	
15	export function isScheduledGame(status?: string): boolean {
16	  return status === SCHEDULED_STATUS;
17	}
18	
19	export function isFinalGame(status?: string): boolean {
20	  return !!status && FINAL_STATUSES.has(status);
21	}
22	
23	export function isInProgressGame(status?: string): boolean {
24	  return !!status && IN_PROGRESS_STATUSES.has(status);
25	}
26	
27	export function shouldShowGameScore(status?: string): boolean {
28	  return !isScheduledGame(status);
29	}
30	
31	export function shouldPollGameStats(status?: string): boolean {
32	  return !isScheduledGame(status) && !isFinalGame(status);
33	}
34	
35	export function shouldShowScheduledOrFinalDate(status?: string): boolean {
36	  return isScheduledGame(status) || isFinalGame(status);
37	}
38	
39	export function shouldShowLiveGameDetails(status?: string): boolean {
40	  return !isScheduledGame(status) && !isFinalGame(status);
41	}
42	
43	export function shouldShowGameChannel(status?: string): boolean {
44	  return !isFinalGame(status);
45	}
46	
47	function isRecentlyStartedGame(isoDate?: string): boolean {
48	  if (!isoDate) {
49	    return false;
50	  }
51	  const startTime = new Date(isoDate).getTime();
52	  if (Number.isNaN(startTime)) {
53	    return false;
54	  }
55	  const now = Date.now();
56	  return (
57	    now >= startTime && now - startTime <= MAX_RECENTLY_STARTED_GAME_AGE_MS
58	  );
59	}
60	
61	export function isLiveDashboardGame(game: Game): boolean {
62	  if (
63	    isFinalGame(game.gameStatus) ||
64	    game.gameStatus === POSTPONED_STATUS ||
65	    !!game.winner ||
66	    game.final === true
67	  ) {
68	    return false;
69	  }
70	
71	  if (isInProgressGame(game.gameStatus)) {
72	    return true;
73	  }
74	
75	  if (isScheduledGame(game.gameStatus)) {
76	    return isRecentlyStartedGame(game.isoDate);
77	  }
78	
79	  return true;
80	}
