94	    // back to a 25-event default), which truncates season-long fetches for
95	    // high-volume leagues like MLB (~2900 games/year). When a response fills the
96	    // limit, bisect the date range and re-fetch each half.
97	    private List<Game> fetchGamesForRange(League league, LocalDate startDate, LocalDate endDate) {
98	        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyyMMdd");
99	        int limit = espnApiProperties.getScoreboard().getLimit();
100	        String gamesUrl = String.format("%s/%s/%s/scoreboard?limit=%d&dates=%s-%s",
101	                espnApiProperties.getBaseUrl(),
102	                league.getSport().getValue(),
103	                league.getValue(),
104	                limit,
105	                startDate.format(formatter),
106	                endDate.format(formatter));
107	        EspnScoreboardResponse espnScoreboardResponse = fetchGamesForUrl(gamesUrl);
108	        if (espnScoreboardResponse == null || espnScoreboardResponse.getEvents() == null) {
109	            return new ArrayList<>();
110	        }
111	        if (espnScoreboardResponse.getEvents().size() >= limit && startDate.isBefore(endDate)) {
112	            LocalDate midDate = startDate.plusDays(ChronoUnit.DAYS.between(startDate, endDate) / 2);
113	            List<Game> games = new ArrayList<>(fetchGamesForRange(league, startDate, midDate));
114	            games.addAll(fetchGamesForRange(league, midDate.plusDays(1), endDate));
115	            return games;
116	        }
117	        return espnScoreboardResponse.getEvents().stream()
118	                .map(event -> espnGameMapper.toGame(event, league))
119	                .filter(Objects::nonNull)
120	                .toList();
121	    }
